CREATE OR REPLACE FUNCTION crm.client_activate(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.client;
BEGIN
  UPDATE crm.client SET active = true
  WHERE id::text = p_id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.client_activate(text) IS 'Activate a client (set active=true) — returns updated row as jsonb';

CREATE OR REPLACE FUNCTION crm.client_archive(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.client;
BEGIN
  UPDATE crm.client SET active = false
  WHERE id::text = p_id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.client_archive(text) IS 'Archive a client (set active=false) — returns updated row as jsonb';

CREATE OR REPLACE FUNCTION crm.client_create(p_row crm.client)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.client;
BEGIN
  INSERT INTO crm.client (type, name, email, phone, address, city, postal_code, tier, tags, notes, active)
  VALUES (p_row.type, p_row.name, p_row.email, p_row.phone, p_row.address, p_row.city, p_row.postal_code,
          COALESCE(p_row.tier, 'standard'), COALESCE(p_row.tags, '{}'), COALESCE(p_row.notes, ''), COALESCE(p_row.active, true))
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.client_create(crm.client) IS 'Create a new client — returns inserted row as jsonb';

CREATE OR REPLACE FUNCTION crm.client_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
