BEGIN
  DELETE FROM crm.client
  WHERE id::text = p_id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.client_delete(text) IS 'Delete a client by id — returns deleted row as jsonb (cascades contacts + interactions)';

CREATE OR REPLACE FUNCTION crm.client_form_fields(p_client crm.client DEFAULT NULL::crm.client)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tags_str text;
BEGIN
  v_tags_str := CASE WHEN p_client.id IS NOT NULL THEN array_to_string(p_client.tags, ', ') ELSE '' END;

  RETURN CASE WHEN p_client.id IS NOT NULL THEN '<input type="hidden" name="id" value="' || p_client.id || '">' ELSE '' END
    || pgv.sel('type', pgv.t('crm.field_type'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.type_individual'), 'value', 'individual'),
         jsonb_build_object('label', pgv.t('crm.type_company'), 'value', 'company')
       ), CASE WHEN p_client.id IS NOT NULL THEN p_client.type ELSE 'individual' END)
    || pgv.input('name', 'text', pgv.t('crm.field_name'), p_client.name, true)
    || pgv.input('email', 'email', pgv.t('crm.field_email'), p_client.email)
    || pgv.input('phone', 'tel', pgv.t('crm.field_phone'), p_client.phone)
    || pgv.input('address', 'text', pgv.t('crm.field_address'), p_client.address)
    || '<div class="grid">'
    || pgv.input('city', 'text', pgv.t('crm.field_city'), p_client.city)
    || pgv.input('postal_code', 'text', pgv.t('crm.field_postal_code'), p_client.postal_code)
    || '</div>'
    || pgv.sel('tier', pgv.t('crm.field_tier'), '["standard","premium","vip"]'::jsonb,
        CASE WHEN p_client.id IS NOT NULL THEN p_client.tier ELSE 'standard' END)
    || pgv.input('tags', 'text', pgv.t('crm.field_tags'), v_tags_str)
    || pgv.textarea('notes', pgv.t('crm.field_notes'), CASE WHEN p_client.id IS NOT NULL AND p_client.notes <> '' THEN p_client.notes ELSE NULL END)
    || CASE WHEN p_client.id IS NOT NULL THEN
        pgv.checkbox('active', pgv.t('crm.field_active'), p_client.active)
       ELSE '' END;
END;
$function$;
COMMENT ON FUNCTION crm.client_form_fields(crm.client) IS 'Helper: returns HTML form fields for client creation/edition (no form wrapper)';

CREATE OR REPLACE FUNCTION crm.client_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(c) || jsonb_build_object(
        'contact_count', (SELECT count(*) FROM crm.contact ct WHERE ct.client_id = c.id),
        'interaction_count', (SELECT count(*) FROM crm.interaction i WHERE i.client_id = c.id)
      )
      FROM crm.client c
      WHERE c.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY c.updated_at DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(c) || jsonb_build_object(
        ''contact_count'', (SELECT count(*) FROM crm.contact ct WHERE ct.client_id = c.id),
        ''interaction_count'', (SELECT count(*) FROM crm.interaction i WHERE i.client_id = c.id)
      )
      FROM crm.client c
      WHERE c.tenant_id = ' || quote_literal(current_setting('app.tenant_id', true))
      || ' AND ' || pgv.rsql_to_where(p_filter, 'crm', 'client')
      || ' ORDER BY c.updated_at DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION crm.client_list(text) IS 'List clients for current tenant with contact/interaction counts — optional RSQL filter';

CREATE OR REPLACE FUNCTION crm.client_options(p_search text DEFAULT NULL::text)
 RETURNS TABLE(value text, label text, detail text)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT
    c.id::text,
    c.name,
    concat_ws(' / ',
      nullif(c.city, ''),
      nullif(c.email, '')
    )
  FROM crm.client c
  WHERE c.active
    AND (p_search IS NULL OR p_search = ''
         OR c.name ILIKE '%' || p_search || '%'
         OR c.email ILIKE '%' || p_search || '%'
         OR c.city ILIKE '%' || p_search || '%')
  ORDER BY c.name
  LIMIT 20;
$function$;
COMMENT ON FUNCTION crm.client_options(text) IS 'Search active clients for select_search — returns value/label/detail rows filtered by ILIKE on name, email, city';

CREATE OR REPLACE FUNCTION crm.client_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT to_jsonb(c) || jsonb_build_object(
    'contacts', COALESCE((SELECT jsonb_agg(to_jsonb(ct) ORDER BY ct.is_primary DESC, ct.name) FROM crm.contact ct WHERE ct.client_id = c.id), '[]'::jsonb),
    'interaction_count', (SELECT count(*) FROM crm.interaction i WHERE i.client_id = c.id)
  ) INTO v_result
  FROM crm.client c
  WHERE c.id::text = p_id AND c.tenant_id = current_setting('app.tenant_id', true);

  IF v_result IS NULL THEN
    RETURN NULL;
  END IF;

  -- HATEOAS actions based on state
  IF (v_result->>'active')::boolean THEN
    v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
      jsonb_build_object('method', 'archive', 'uri', 'crm://client/' || p_id || '/archive'),
      jsonb_build_object('method', 'delete', 'uri', 'crm://client/' || p_id)
    ));
  ELSE
    v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
      jsonb_build_object('method', 'activate', 'uri', 'crm://client/' || p_id || '/activate'),
      jsonb_build_object('method', 'delete', 'uri', 'crm://client/' || p_id)
    ));
  END IF;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION crm.client_read(text) IS 'Read client by id — returns enriched jsonb with contacts and interaction count';

CREATE OR REPLACE FUNCTION crm.client_update(p_row crm.client)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.client;
BEGIN
  UPDATE crm.client SET
    type = p_row.type,
    name = p_row.name,
    email = p_row.email,
    phone = p_row.phone,
    address = p_row.address,
    city = p_row.city,
    postal_code = p_row.postal_code,
    tier = p_row.tier,
    tags = p_row.tags,
    notes = p_row.notes,
    active = p_row.active
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.client_update(crm.client) IS 'Update a client by id — returns updated row as jsonb';

CREATE OR REPLACE FUNCTION crm.client_view()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN jsonb_build_object(
    'uri', 'crm://client',
    'label', 'crm.entity_client',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('name', 'type', 'tier')
      ),

      'standard', jsonb_build_object(
        'fields', jsonb_build_array('type', 'email', 'phone', 'city', 'tier'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'quote_count', 'label', 'crm.stat_quotes'),
          jsonb_build_object('key', 'total_revenue', 'label', 'crm.stat_revenue'),
          jsonb_build_object('key', 'pending_amount', 'label', 'crm.stat_pending')
        )
      ),

      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('type', 'email', 'phone', 'address', 'city', 'postal_code', 'tier', 'tags', 'notes', 'created_at'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'quote_count', 'label', 'crm.stat_quotes'),
          jsonb_build_object('key', 'total_revenue', 'label', 'crm.stat_revenue'),
          jsonb_build_object('key', 'pending_amount', 'label', 'crm.stat_pending'),
          jsonb_build_object('key', 'contact_count', 'label', 'crm.col_contacts'),
          jsonb_build_object('key', 'interaction_count', 'label', 'crm.col_interactions')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'quote://estimate', 'filter', 'client_id={id}', 'label', 'crm.related_quotes'),
          jsonb_build_object('entity', 'quote://invoice', 'filter', 'client_id={id}', 'label', 'crm.related_invoices')
        )
      ),

      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object('label', 'crm.section_identity', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'type', 'label', 'crm.field_type', 'type', 'select',
              'options', jsonb_build_array(
                jsonb_build_object('label', 'crm.type_individual', 'value', 'individual'),
                jsonb_build_object('label', 'crm.type_company', 'value', 'company')
              ), 'required', true),
            jsonb_build_object('key', 'name', 'label', 'crm.field_name', 'type', 'text', 'required', true),
            jsonb_build_object('key', 'tier', 'label', 'crm.field_tier', 'type', 'select',
              'options', jsonb_build_array(
                jsonb_build_object('label', 'Standard', 'value', 'standard'),
                jsonb_build_object('label', 'Premium', 'value', 'premium'),
                jsonb_build_object('label', 'VIP', 'value', 'vip')
              ))
          )),
          jsonb_build_object('label', 'crm.section_contact', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'email', 'label', 'crm.field_email', 'type', 'email'),
            jsonb_build_object('key', 'phone', 'label', 'crm.field_phone', 'type', 'tel')
          )),
          jsonb_build_object('label', 'crm.section_address', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'address', 'label', 'crm.field_address', 'type', 'text'),
            jsonb_build_object('key', 'city', 'label', 'crm.field_city', 'type', 'text'),
            jsonb_build_object('key', 'postal_code', 'label', 'crm.field_postal_code', 'type', 'text')
          )),
          jsonb_build_object('label', 'crm.section_notes', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'tags', 'label', 'crm.field_tags', 'type', 'text'),
            jsonb_build_object('key', 'notes', 'label', 'crm.field_notes', 'type', 'textarea')
          ))
        )
      )
    ),

    'actions', jsonb_build_object(
      'archive', jsonb_build_object('label', 'crm.action_archive', 'variant', 'warning', 'confirm', 'crm.confirm_archive'),
      'activate', jsonb_build_object('label', 'crm.action_activate'),
      'delete', jsonb_build_object('label', 'crm.action_delete', 'variant', 'danger', 'confirm', 'crm.confirm_delete_client')
    )
  );
END;
$function$;
COMMENT ON FUNCTION crm.client_view() IS 'View template for client entity: compact, standard, expanded, form, actions';

CREATE OR REPLACE FUNCTION crm.display_name(p_client crm.client)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT CASE
    WHEN p_client.type = 'company' AND p_client.city IS NOT NULL
      THEN p_client.name || ' (' || p_client.city || ')'
    ELSE p_client.name
  END;
$function$;
COMMENT ON FUNCTION crm.display_name(crm.client) IS 'Display name for a client — name + city for companies';

