CREATE OR REPLACE FUNCTION crm.interaction_create(p_row crm.interaction)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.interaction;
BEGIN
  INSERT INTO crm.interaction (client_id, type, subject, body)
  VALUES (p_row.client_id, p_row.type, p_row.subject, COALESCE(p_row.body, ''))
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.interaction_create(crm.interaction) IS 'Create a new interaction — returns inserted row as jsonb';

CREATE OR REPLACE FUNCTION crm.interaction_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.interaction;
BEGIN
  DELETE FROM crm.interaction
  WHERE id::text = p_id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.interaction_delete(text) IS 'Delete an interaction by id — returns deleted row as jsonb';

CREATE OR REPLACE FUNCTION crm.interaction_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(i) || jsonb_build_object('client_name', c.name)
      FROM crm.interaction i
      JOIN crm.client c ON c.id = i.client_id
      WHERE i.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY i.created_at DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(i) || jsonb_build_object(''client_name'', c.name)
       FROM crm.interaction i
       JOIN crm.client c ON c.id = i.client_id
       WHERE i.tenant_id = ' || quote_literal(current_setting('app.tenant_id', true))
       || ' AND ' || pgv.rsql_to_where(p_filter, 'crm', 'interaction')
       || ' ORDER BY i.created_at DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION crm.interaction_list(text) IS 'List interactions for current tenant with client name resolved — optional RSQL filter';

CREATE OR REPLACE FUNCTION crm.interaction_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT to_jsonb(i) || jsonb_build_object('client_name', c.name)
  INTO v_result
  FROM crm.interaction i
  JOIN crm.client c ON c.id = i.client_id
  WHERE i.id::text = p_id AND i.tenant_id = current_setting('app.tenant_id', true);

  IF v_result IS NULL THEN
    RETURN NULL;
  END IF;

  -- HATEOAS actions (interactions are append-only, only delete available)
  v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
    jsonb_build_object('method', 'delete', 'uri', 'crm://interaction/' || p_id)
  ));

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION crm.interaction_read(text) IS 'Read interaction by id — returns enriched jsonb with client name';

CREATE OR REPLACE FUNCTION crm.interaction_update(p_row crm.interaction)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result crm.interaction;
BEGIN
  UPDATE crm.interaction SET
    type = p_row.type,
    subject = p_row.subject,
    body = p_row.body
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_result;
  RETURN to_jsonb(v_result);
END;
$function$;
COMMENT ON FUNCTION crm.interaction_update(crm.interaction) IS 'Update an interaction by id — returns updated row as jsonb';

CREATE OR REPLACE FUNCTION crm.interaction_view()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN jsonb_build_object(
    'uri', 'crm://interaction',
    'label', 'crm.entity_interaction',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('subject', 'type', 'client_name')
      ),

      'standard', jsonb_build_object(
        'fields', jsonb_build_array('type', 'subject', 'client_name', 'created_at')
      ),

      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('type', 'subject', 'body', 'client_name', 'created_at')
      ),

      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object('label', 'crm.section_interaction', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'client_id', 'label', 'crm.col_client', 'type', 'combobox', 'source', 'crm://client', 'display', 'name', 'required', true),
            jsonb_build_object('key', 'type', 'label', 'crm.field_type', 'type', 'select', 'required', true,
              'options', jsonb_build_array(
                jsonb_build_object('label', 'crm.type_call', 'value', 'call'),
                jsonb_build_object('label', 'crm.type_visit', 'value', 'visit'),
                jsonb_build_object('label', 'crm.type_email', 'value', 'email'),
                jsonb_build_object('label', 'crm.type_note', 'value', 'note')
              )),
            jsonb_build_object('key', 'subject', 'label', 'crm.field_subject', 'type', 'text', 'required', true),
            jsonb_build_object('key', 'body', 'label', 'crm.field_details', 'type', 'textarea')
          ))
        )
      )
    ),

    'actions', jsonb_build_object(
      'delete', jsonb_build_object('label', 'crm.action_delete', 'variant', 'danger', 'confirm', 'crm.confirm_delete_interaction')
    )
  );
END;
$function$;
COMMENT ON FUNCTION crm.interaction_view() IS 'View template for interaction entity: compact, standard, expanded, form, actions';

CREATE OR REPLACE FUNCTION crm.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('href', '/', 'label', pgv.t('crm.nav_clients'), 'icon', 'users', 'entity', 'client'),
    jsonb_build_object('href', '/interactions', 'label', pgv.t('crm.nav_interactions'), 'icon', 'message-circle', 'entity', 'interaction'),
    jsonb_build_object('href', '/import', 'label', pgv.t('crm.nav_import'), 'icon', 'upload')
  );
$function$;
COMMENT ON FUNCTION crm.nav_items() IS 'Navigation items for CRM module (i18n)';

CREATE OR REPLACE FUNCTION crm.tier_variant(p_tier text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_tier
    WHEN 'vip' THEN 'warning'
    WHEN 'premium' THEN 'primary'
    ELSE 'default'
  END;
$function$;
COMMENT ON FUNCTION crm.tier_variant(text) IS 'Map client tier to pgv.badge variant';

CREATE OR REPLACE FUNCTION crm.type_label(p_type text)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT CASE p_type
    WHEN 'individual' THEN pgv.t('crm.type_individual')
    WHEN 'company' THEN pgv.t('crm.type_company')
    WHEN 'call' THEN pgv.t('crm.type_call')
    WHEN 'visit' THEN pgv.t('crm.type_visit')
    WHEN 'email' THEN pgv.t('crm.type_email')
    WHEN 'note' THEN pgv.t('crm.type_note')
    ELSE p_type
  END;
$function$;
COMMENT ON FUNCTION crm.type_label(text) IS 'Translate type codes to localized labels via i18n';

CREATE OR REPLACE FUNCTION crm.client_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client crm.client;
  v_contacts jsonb;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('crm.nav_clients')),
        pgv.ui_table('clients', jsonb_build_array(
          pgv.ui_col('name', pgv.t('crm.col_client'), pgv.ui_link('{name}', '/crm/client/{id}')),
          pgv.ui_col('type', pgv.t('crm.col_type')),
          pgv.ui_col('city', pgv.t('crm.col_city')),
          pgv.ui_col('tier', pgv.t('crm.col_tier'), pgv.ui_badge('{tier}')),
          pgv.ui_col('contact_count', pgv.t('crm.col_contacts')),
          pgv.ui_col('interaction_count', pgv.t('crm.col_interactions')),
          pgv.ui_col('active', pgv.t('crm.col_active'))
        ))
      ),
      'datasources', jsonb_build_object(
        'clients', pgv.ui_datasource('crm://client', 20, true, '-updated_at')
      )
    );
  END IF;

  -- Detail mode
  SELECT * INTO v_client FROM crm.client WHERE id::text = p_slug AND tenant_id = current_setting('app.tenant_id', true);
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  SELECT COALESCE(jsonb_agg(to_jsonb(ct) ORDER BY ct.is_primary DESC, ct.name), '[]'::jsonb)
    INTO v_contacts
    FROM crm.contact ct WHERE ct.client_id = v_client.id;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      -- Header
      pgv.ui_row(
        pgv.ui_link(E'\u2190 ' || pgv.t('crm.nav_clients'), '/crm'),
        pgv.ui_heading(v_client.name)
      ),
      pgv.ui_row(
        pgv.ui_badge(crm.type_label(v_client.type)),
        pgv.ui_badge(upper(v_client.tier), crm.tier_variant(v_client.tier)),
        CASE WHEN v_client.active THEN pgv.ui_badge(pgv.t('crm.yes'), 'success') ELSE pgv.ui_badge(pgv.t('crm.no'), 'error') END
      ),

      -- Coordonnées
      pgv.ui_heading(pgv.t('crm.title_fiche'), 3),
      pgv.ui_row(
        pgv.ui_text(pgv.t('crm.field_email') || ': ' || COALESCE(v_client.email, '—')),
        pgv.ui_text(pgv.t('crm.field_phone') || ': ' || COALESCE(v_client.phone, '—'))
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('crm.field_address') || ': ' || COALESCE(v_client.address, '—')),
        pgv.ui_text(pgv.t('crm.field_city') || ': ' || COALESCE(v_client.city, '—')),
        pgv.ui_text(pgv.t('crm.field_postal_code') || ': ' || COALESCE(v_client.postal_code, '—'))
      ),
      pgv.ui_text(pgv.t('crm.field_notes') || ': ' || CASE WHEN v_client.notes = '' THEN '—' ELSE v_client.notes END),

      -- Contacts
      pgv.ui_heading(pgv.t('crm.title_contacts'), 3),
      pgv.ui_text(v_contacts::text)
    )
  );
END;
$function$;
COMMENT ON FUNCTION crm.client_ui(text) IS 'SDUI view: client list (table+datasource) or detail (static sections)';

CREATE OR REPLACE FUNCTION crm.interaction_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_i crm.interaction;
  v_client_name text;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('crm.nav_interactions')),
        pgv.ui_table('interactions', jsonb_build_array(
          pgv.ui_col('subject', pgv.t('crm.field_subject'), pgv.ui_link('{subject}', '/crm/interaction/{id}')),
          pgv.ui_col('type', pgv.t('crm.field_type'), pgv.ui_badge('{type}')),
          pgv.ui_col('client_name', pgv.t('crm.col_client'), pgv.ui_link('{client_name}', '/crm/client/{client_id}')),
          pgv.ui_col('created_at', pgv.t('crm.col_date'))
        ))
      ),
      'datasources', jsonb_build_object(
        'interactions', pgv.ui_datasource('crm://interaction', 20, true, '-created_at')
      )
    );
  END IF;

  -- Detail mode
  SELECT * INTO v_i FROM crm.interaction WHERE id::text = p_slug AND tenant_id = current_setting('app.tenant_id', true);
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  SELECT name INTO v_client_name FROM crm.client WHERE id = v_i.client_id;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link(E'\u2190 ' || pgv.t('crm.nav_interactions'), '/crm/interactions'),
        pgv.ui_heading(v_i.subject)
      ),
      pgv.ui_row(
        pgv.ui_badge(crm.type_label(v_i.type), CASE v_i.type WHEN 'call' THEN 'info' WHEN 'visit' THEN 'success' WHEN 'email' THEN 'warning' ELSE 'info' END),
        pgv.ui_link(v_client_name, '/crm/client/' || v_i.client_id)
      ),
      pgv.ui_text(CASE WHEN v_i.body = '' THEN '—' ELSE v_i.body END),
      pgv.ui_text(to_char(v_i.created_at, 'DD/MM/YYYY HH24:MI'))
    )
  );
END;
$function$;
COMMENT ON FUNCTION crm.interaction_ui(text) IS 'SDUI view: interaction list (table+datasource) or detail (static view)';

